def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item > cap * 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        decay_factor = 1.0
        interaction_term = 0.0
        boost_factor = 1.0
        penalty_factor = 0.0
        ratio = item / cap
        for outer in range(1, 15):
            temp_sum = 0.0
            for inner in range(outer, outer + 5):
                if inner % 4 == 0:
                    decay_factor *= 1.03 + 0.02 * (inner % 7)
                elif inner % 6 == 0:
                    decay_factor *= 0.97 - 0.015 * (inner % 5)
                contrib = (np.tanh(ratio * inner) + np.cos(inner / (ratio + 1))) * decay_factor
                if (cap + inner) % 13 == 0:
                    contrib *= 1.07
                elif (cap * inner) % 9 == 0:
                    contrib *= 0.93
                temp_sum += contrib
            base_score += temp_sum / (outer + 3)
            if outer % 5 == 2:
                penalty_factor += np.log1p(abs(cap - item * outer)) / (outer + 2)
            else:
                penalty_factor -= np.sqrt(abs(cap - item * outer)) / (outer + 4)
            if outer % 3 == 0:
                interaction_term += np.sin(ratio * outer * np.pi / 2) * (outer % 4 + 1)
            if outer == 7:
                for sub in range(1, 4):
                    diff = cap - item * (sub ** 3)
                    if diff > 0:
                        if diff % (sub + 3) == 0:
                            penalty_factor -= np.exp(-diff / (sub + 2))
                        else:
                            penalty_factor += np.log1p(diff) / (sub + 1)
                    else:
                        penalty_factor += abs(diff) ** 0.9 / (sub + 5)
            if ratio > 0.7 and outer % 2 == 1:
                boost_factor *= 1.12 + 0.015 * outer
            elif ratio < 0.15 and outer % 4 == 0:
                boost_factor *= 0.88 - 0.02 * outer
            if outer % 6 == 1 and cap % (outer + 2) == 0:
                penalty_factor += np.cos(outer * ratio) * 0.7
        total_score = (base_score + interaction_term) * boost_factor - penalty_factor * 0.9
        if total_score < 0:
            priorities[i] = -total_score * (np.sqrt(cap + item) + np.log1p(cap))
        else:
            if cap > item * 3:
                priorities[i] = -total_score / (np.cbrt(cap) + 2) * (1 + ratio * 0.8)
            else:
                priorities[i] = -total_score / (cap + 5) * np.exp(-ratio**1.5)
        if ratio > 0.9:
            priorities[i] *= 1.18 + 0.05 * np.sin(cap)
        elif ratio < 0.1:
            priorities[i] *= 0.7 - 0.03 * np.cos(cap)
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 2 == 1:
            priorities[i] *= 1.03
    return priorities
